"""
BNPL Loan Default Prediction - Flask App
All models embedded as base64 PKL data (no external pkl files needed)
"""
import base64, io, json
import numpy as np
import joblib
from flask import Flask, request, jsonify, render_template_string

# === Embedded Model Data ===
_PKL_LR  = ""
_PKL_RF  = ""
_PKL_GBT = ""
_PKL_SCL = ""
_PKL_LE  = ""

def _load(b64):
    return joblib.load(io.BytesIO(base64.b64decode(b64)))

MODELS = {
    "logistic_regression": _load(_PKL_LR),
    "random_forest":       _load(_PKL_RF),
    "gradient_boosting":   _load(_PKL_GBT),
}
SCALER  = _load(_PKL_SCL)
LE_DICT = _load(_PKL_LE)

LABEL_COLS   = ["Education", "EmploymentType", "MaritalStatus", "LoanPurpose"]
BINARY_COLS  = ["HasMortgage", "HasDependents", "HasCoSigner"]
FEATURE_ORDER = [
    "Age","Income","LoanAmount","CreditScore","MonthsEmployed",
    "NumCreditLines","InterestRate","LoanTerm","DTIRatio",
    "Education","EmploymentType","MaritalStatus",
    "HasMortgage","HasDependents","LoanPurpose","HasCoSigner"
]
CATEGORIES = {col: list(LE_DICT[col].classes_) for col in LABEL_COLS}

HTML = r"""
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>BNPL Default Predictor</title>
<style>
  :root{--bg:#0f172a;--card:#1e293b;--accent:#6366f1;--accent2:#22d3ee;--text:#f1f5f9;--muted:#94a3b8;--border:#334155;--danger:#ef4444;--success:#22c55e}
  *{box-sizing:border-box;margin:0;padding:0}
  body{background:var(--bg);color:var(--text);font-family:'Segoe UI',sans-serif;min-height:100vh;padding:2rem 1rem}
  h1{text-align:center;font-size:2rem;background:linear-gradient(135deg,var(--accent),var(--accent2));-webkit-background-clip:text;-webkit-text-fill-color:transparent;margin-bottom:.3rem}
  .subtitle{text-align:center;color:var(--muted);margin-bottom:2rem;font-size:.95rem}
  .container{max-width:900px;margin:0 auto}
  .card{background:var(--card);border:1px solid var(--border);border-radius:16px;padding:1.8rem;margin-bottom:1.5rem}
  .card h2{font-size:1.1rem;color:var(--accent2);margin-bottom:1.2rem}
  .grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:1rem}
  label{font-size:.82rem;color:var(--muted);display:block;margin-bottom:.3rem}
  input,select{width:100%;padding:.55rem .8rem;background:#0f172a;border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:.9rem;outline:none;transition:border .2s}
  input:focus,select:focus{border-color:var(--accent)}
  .model-select{display:flex;gap:.8rem;flex-wrap:wrap;margin-bottom:1rem}
  .model-btn{padding:.5rem 1.2rem;border-radius:8px;border:1px solid var(--border);background:transparent;color:var(--muted);cursor:pointer;font-size:.85rem;transition:all .2s}
  .model-btn.active{background:var(--accent);border-color:var(--accent);color:#fff}
  .btn{width:100%;padding:.8rem;border-radius:10px;border:none;background:linear-gradient(135deg,var(--accent),#818cf8);color:#fff;font-size:1rem;font-weight:600;cursor:pointer;margin-top:1rem;transition:opacity .2s}
  .btn:hover{opacity:.88}
  #result{display:none;margin-top:1.5rem}
  .risk-meter{height:12px;border-radius:6px;background:#1e293b;border:1px solid var(--border);overflow:hidden;margin:.8rem 0}
  .risk-fill{height:100%;border-radius:6px;transition:width .8s ease}
  .risk-high{background:linear-gradient(90deg,#f97316,var(--danger))}
  .risk-low{background:linear-gradient(90deg,#16a34a,var(--success))}
  .verdict{font-size:1.4rem;font-weight:700;margin:.5rem 0}
  .verdict.high{color:var(--danger)}
  .verdict.low{color:var(--success)}
  .prob-text{font-size:2.5rem;font-weight:800}
  .all-models{display:grid;grid-template-columns:repeat(3,1fr);gap:.8rem;margin-top:1rem}
  .model-result{background:#0f172a;border:1px solid var(--border);border-radius:10px;padding:.8rem;text-align:center}
  .model-result .name{font-size:.75rem;color:var(--muted);margin-bottom:.3rem}
  .model-result .score{font-size:1.3rem;font-weight:700}
  @media(max-width:600px){.all-models{grid-template-columns:1fr}}
</style>
</head>
<body>
<div class="container">
  <h1>🏦 BNPL Default Predictor</h1>
  <p class="subtitle">Buy Now Pay Later &middot; Loan Default Risk Assessment</p>

  <div class="card">
    <h2>📊 Personal &amp; Financial Details</h2>
    <div class="grid">
      <div><label>Age</label><input type="number" id="Age" value="35" min="18" max="100"></div>
      <div><label>Annual Income ($)</label><input type="number" id="Income" value="60000"></div>
      <div><label>Loan Amount ($)</label><input type="number" id="LoanAmount" value="15000"></div>
      <div><label>Credit Score</label><input type="number" id="CreditScore" value="680" min="300" max="850"></div>
      <div><label>Months Employed</label><input type="number" id="MonthsEmployed" value="36"></div>
      <div><label>Num Credit Lines</label><input type="number" id="NumCreditLines" value="3"></div>
      <div><label>Interest Rate (%)</label><input type="number" id="InterestRate" value="12.5" step="0.1"></div>
      <div><label>Loan Term (months)</label><input type="number" id="LoanTerm" value="36"></div>
      <div><label>DTI Ratio</label><input type="number" id="DTIRatio" value="0.35" step="0.01"></div>
    </div>
  </div>

  <div class="card">
    <h2>🧑‍💼 Profile</h2>
    <div class="grid">
      <div><label>Education</label>
        <select id="Education">
          {% for e in categories.Education %}<option>{{ e }}</option>{% endfor %}
        </select>
      </div>
      <div><label>Employment Type</label>
        <select id="EmploymentType">
          {% for e in categories.EmploymentType %}<option>{{ e }}</option>{% endfor %}
        </select>
      </div>
      <div><label>Marital Status</label>
        <select id="MaritalStatus">
          {% for e in categories.MaritalStatus %}<option>{{ e }}</option>{% endfor %}
        </select>
      </div>
      <div><label>Loan Purpose</label>
        <select id="LoanPurpose">
          {% for e in categories.LoanPurpose %}<option>{{ e }}</option>{% endfor %}
        </select>
      </div>
      <div><label>Has Mortgage</label>
        <select id="HasMortgage"><option>No</option><option>Yes</option></select>
      </div>
      <div><label>Has Dependents</label>
        <select id="HasDependents"><option>No</option><option>Yes</option></select>
      </div>
      <div><label>Has Co-Signer</label>
        <select id="HasCoSigner"><option>No</option><option>Yes</option></select>
      </div>
    </div>
  </div>

  <div class="card">
    <h2>🤖 Model Selection</h2>
    <div class="model-select">
      <button class="model-btn active" onclick="selectModel(this,'logistic_regression')">Logistic Regression</button>
      <button class="model-btn" onclick="selectModel(this,'random_forest')">Random Forest</button>
      <button class="model-btn" onclick="selectModel(this,'gradient_boosting')">Gradient Boosting</button>
    </div>
    <button class="btn" onclick="predict()">🔍 Predict Default Risk</button>
  </div>

  <div id="result" class="card">
    <h2>📈 Prediction Result</h2>
    <div style="text-align:center;padding:1rem 0">
      <div class="prob-text" id="probText">—</div>
      <div style="color:var(--muted);font-size:.85rem">Default Probability</div>
      <div class="risk-meter"><div class="risk-fill" id="riskFill" style="width:0%"></div></div>
      <div class="verdict" id="verdict"></div>
    </div>
    <h2 style="margin-top:1rem">All Models Comparison</h2>
    <div class="all-models">
      <div class="model-result"><div class="name">Logistic Regression</div><div class="score" id="s_lr">—</div></div>
      <div class="model-result"><div class="name">Random Forest</div><div class="score" id="s_rf">—</div></div>
      <div class="model-result"><div class="name">Gradient Boosting</div><div class="score" id="s_gb">—</div></div>
    </div>
  </div>
</div>

<script>
let selectedModel = 'logistic_regression';
function selectModel(btn, name){
  document.querySelectorAll('.model-btn').forEach(b=>b.classList.remove('active'));
  btn.classList.add('active');
  selectedModel = name;
}
function g(id){ return document.getElementById(id).value; }
async function predict(){
  const payload = {
    model: selectedModel,
    Age: +g('Age'), Income: +g('Income'), LoanAmount: +g('LoanAmount'),
    CreditScore: +g('CreditScore'), MonthsEmployed: +g('MonthsEmployed'),
    NumCreditLines: +g('NumCreditLines'), InterestRate: +g('InterestRate'),
    LoanTerm: +g('LoanTerm'), DTIRatio: +g('DTIRatio'),
    Education: g('Education'), EmploymentType: g('EmploymentType'),
    MaritalStatus: g('MaritalStatus'), LoanPurpose: g('LoanPurpose'),
    HasMortgage: g('HasMortgage'), HasDependents: g('HasDependents'),
    HasCoSigner: g('HasCoSigner')
  };
  const res = await fetch('/predict', {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});
  const data = await res.json();
  if(data.error){ alert(data.error); return; }
  const pct = (data.probability * 100).toFixed(1);
  document.getElementById('probText').textContent = pct + '%';
  const fill = document.getElementById('riskFill');
  fill.style.width = pct + '%';
  fill.className = 'risk-fill ' + (data.probability > 0.5 ? 'risk-high' : 'risk-low');
  const v = document.getElementById('verdict');
  v.textContent = data.default_predicted ? '⚠️ HIGH DEFAULT RISK' : '✅ LOW DEFAULT RISK';
  v.className = 'verdict ' + (data.default_predicted ? 'high' : 'low');
  document.getElementById('s_lr').textContent = (data.all_models.logistic_regression*100).toFixed(1)+'%';
  document.getElementById('s_rf').textContent = (data.all_models.random_forest*100).toFixed(1)+'%';
  document.getElementById('s_gb').textContent = (data.all_models.gradient_boosting*100).toFixed(1)+'%';
  document.getElementById('result').style.display='block';
  document.getElementById('result').scrollIntoView({behavior:'smooth'});
}
</script>
</body>
</html>
"""

app = Flask(__name__)

def preprocess(data):
    feat = {}
    for col in BINARY_COLS:
        feat[col] = 1 if data.get(col, "No") == "Yes" else 0
    for col in LABEL_COLS:
        le = LE_DICT[col]
        val = data.get(col, le.classes_[0])
        feat[col] = int(le.transform([val])[0])
    for col in ["Age","Income","LoanAmount","CreditScore","MonthsEmployed",
                "NumCreditLines","InterestRate","LoanTerm","DTIRatio"]:
        feat[col] = float(data.get(col, 0))
    X = np.array([[feat[c] for c in FEATURE_ORDER]])
    return SCALER.transform(X)

@app.route("/")
def index():
    return render_template_string(HTML, categories=CATEGORIES)

@app.route("/predict", methods=["POST"])
def predict():
    try:
        data = request.get_json()
        model_name = data.get("model", "gradient_boosting")
        if model_name not in MODELS:
            return jsonify({"error": f"Unknown model '{model_name}'"}), 400
        X = preprocess(data)
        all_probs = {name: float(m.predict_proba(X)[0, 1]) for name, m in MODELS.items()}
        prob = all_probs[model_name]
        return jsonify({
            "probability": prob,
            "default_predicted": bool(prob > 0.5),
            "model_used": model_name,
            "all_models": all_probs
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 400

if __name__ == "__main__":
    print("Starting BNPL Default Prediction API on http://localhost:5000")
    app.run(debug=True, port=5000)
